import React, { useState, useRef } from 'react';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || '';

const FIELD_LABELS = {
  name: 'Name',
  dob: 'Date of Birth',
  gender: 'Gender',
  careof: 'Care Of',
  house: 'House',
  street: 'Street',
  location: 'Location',
  landmark: 'Landmark',
  vtc: 'Village/Town/City',
  postoffice: 'Post Office',
  subdistrict: 'Sub District',
  district: 'District',
  state: 'State',
  pincode: 'Pincode',
  referenceid: 'Reference ID',
  aadhaar_last_4_digit: 'Aadhaar (Last 4 Digits)',
  email_mobile_status: 'Email/Mobile Status',
  email: 'Email Registered',
  mobile: 'Mobile Registered',
  uid: 'UID',
  yob: 'Year of Birth',
  gname: 'Guardian Name',
  lm: 'Landmark',
  loc: 'Locality',
  vtc_name: 'VTC',
  po: 'Post Office',
  dist: 'District',
  subdist: 'Sub District',
  last_4_digits_mobile_no: 'Last 4 Digits (Mobile)',
  version: 'QR Version',
};

const SKIP_FIELDS = ['email_mobile_status'];

function FieldValue({ value }) {
  if (typeof value === 'boolean') {
    return (
      <span className={`badge ${value ? 'badge-yes' : 'badge-no'}`}>
        {value ? 'Yes' : 'No'}
      </span>
    );
  }
  return <span>{String(value)}</span>;
}

function AadhaarResult({ result }) {
  const { qr_type, data, has_image, photo } = result;

  return (
    <div className="result-card">
      <div className="result-header">
        <h2>Decoded Successfully</h2>
        <span className="qr-type-badge">{qr_type}</span>
      </div>

      <div className="result-body">
        {has_image && photo && (
          <div className="photo-section">
            <img
              src={`data:image/jpeg;base64,${photo}`}
              alt="Aadhaar Photo"
              className="aadhaar-photo"
            />
          </div>
        )}

        <div className="fields-grid">
          {Object.entries(data)
            .filter(([key]) => !SKIP_FIELDS.includes(key))
            .map(([key, value]) => (
              <div className="field-row" key={key}>
                <span className="field-label">
                  {FIELD_LABELS[key] || key}
                </span>
                <span className="field-value">
                  <FieldValue value={value} />
                </span>
              </div>
            ))}
        </div>
      </div>
    </div>
  );
}

function PdfConverter() {
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [pages, setPages] = useState(null);
  const [error, setError] = useState(null);
  const inputRef = useRef();

  const handleFile = (selected) => {
    if (!selected) return;
    setFile(selected);
    setPages(null);
    setError(null);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    const dropped = e.dataTransfer.files[0];
    if (dropped) handleFile(dropped);
  };

  const handleConvert = async () => {
    if (!file) return;
    setLoading(true);
    setPages(null);
    setError(null);

    const formData = new FormData();
    formData.append('pdf', file);

    try {
      const res = await fetch(`${API_URL}/api/pdf-to-jpg`, {
        method: 'POST',
        body: formData,
      });
      const json = await res.json();
      if (!res.ok || json.error) {
        setError(json.error || 'Something went wrong');
      } else {
        setPages(json.pages);
      }
    } catch {
      setError('Could not connect to server. Make sure the backend is running on port 5000.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = (page) => {
    const link = document.createElement('a');
    link.href = `data:image/jpeg;base64,${page.image}`;
    const baseName = file ? file.name.replace(/\.pdf$/i, '') : 'document';
    link.download = `${baseName}-page-${page.page}.jpg`;
    link.click();
  };

  const handleReset = () => {
    setFile(null);
    setPages(null);
    setError(null);
  };

  return (
    <div className="upload-section">
      <div
        className={`drop-zone ${file ? 'has-file' : ''}`}
        onDrop={handleDrop}
        onDragOver={(e) => e.preventDefault()}
        onClick={() => inputRef.current.click()}
      >
        <input
          ref={inputRef}
          type="file"
          accept=".pdf"
          style={{ display: 'none' }}
          onChange={(e) => handleFile(e.target.files[0])}
        />
        {file ? (
          <div className="drop-placeholder">
            <div className="upload-icon" style={{ color: '#e53e3e' }}>&#128196;</div>
            <p><strong>{file.name}</strong></p>
          </div>
        ) : (
          <div className="drop-placeholder">
            <div className="upload-icon">&#8679;</div>
            <p>Drag &amp; drop or <strong>click to upload</strong></p>
            <p className="hint">PDF files only</p>
          </div>
        )}
      </div>

      {error && <div className="error-box">{error}</div>}

      <div className="action-buttons">
        <button
          className="btn btn-primary"
          onClick={handleConvert}
          disabled={!file || loading}
        >
          {loading ? 'Converting...' : 'Convert to JPG'}
        </button>
        {file && (
          <button className="btn btn-secondary" onClick={handleReset}>
            Clear
          </button>
        )}
      </div>

      {pages && (
        <div className="pdf-pages">
          <h3 className="pdf-pages-title">
            {pages.length} page{pages.length !== 1 ? 's' : ''} converted
          </h3>
          <div className="pdf-pages-grid">
            {pages.map((page) => (
              <div className="pdf-page-card" key={page.page}>
                <img
                  src={`data:image/jpeg;base64,${page.image}`}
                  alt={`Page ${page.page}`}
                  className="pdf-page-img"
                />
                <button
                  className="btn btn-secondary pdf-download-btn"
                  onClick={() => handleDownload(page)}
                >
                  &#8595; Page {page.page}
                </button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default function App() {
  const [mode, setMode] = useState('qr');
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const inputRef = useRef();

  const handleFile = (selected) => {
    if (!selected) return;
    setFile(selected);
    setResult(null);
    setError(null);
    setPreview(URL.createObjectURL(selected));
  };

  const handleDrop = (e) => {
    e.preventDefault();
    const dropped = e.dataTransfer.files[0];
    if (dropped) handleFile(dropped);
  };

  const handleSubmit = async () => {
    if (!file) return;
    setLoading(true);
    setResult(null);
    setError(null);

    const formData = new FormData();
    formData.append('image', file);

    try {
      const res = await fetch(`${API_URL}/api/decode`, {
        method: 'POST',
        body: formData,
      });
      const json = await res.json();
      if (!res.ok || json.error) {
        setError(json.error || 'Something went wrong');
      } else {
        setResult(json);
      }
    } catch {
      setError('Could not connect to server. Make sure the backend is running on port 5000.');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
  };

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-content">
          <div className="logo">&#9632;</div>
          <div>
            <h1>Aadhaar QR Decoder</h1>
            <p>Upload an Aadhaar card image to extract details from its QR code</p>
          </div>
        </div>
      </header>

      <main className="app-main">
        <div className="tab-bar">
          <button
            className={`tab-btn${mode === 'qr' ? ' active' : ''}`}
            onClick={() => setMode('qr')}
          >
            QR Decoder
          </button>
          <button
            className={`tab-btn${mode === 'pdf' ? ' active' : ''}`}
            onClick={() => setMode('pdf')}
          >
            PDF to JPG
          </button>
        </div>

        {mode === 'pdf' && <PdfConverter />}

        {mode === 'qr' && !result && (
          <div className="upload-section">
            <div
              className={`drop-zone ${file ? 'has-file' : ''}`}
              onDrop={handleDrop}
              onDragOver={(e) => e.preventDefault()}
              onClick={() => inputRef.current.click()}
            >
              <input
                ref={inputRef}
                type="file"
                accept="image/*"
                style={{ display: 'none' }}
                onChange={(e) => handleFile(e.target.files[0])}
              />
              {preview ? (
                <img src={preview} alt="Preview" className="preview-img" />
              ) : (
                <div className="drop-placeholder">
                  <div className="upload-icon">&#8679;</div>
                  <p>Drag &amp; drop or <strong>click to upload</strong></p>
                  <p className="hint">Supports JPG, PNG, JPEG, BMP, WEBP</p>
                </div>
              )}
            </div>

            {file && (
              <p className="filename">Selected: <strong>{file.name}</strong></p>
            )}

            {error && (
              <div className="error-box">{error}</div>
            )}

            <div className="action-buttons">
              <button
                className="btn btn-primary"
                onClick={handleSubmit}
                disabled={!file || loading}
              >
                {loading ? 'Decoding...' : 'Decode QR Code'}
              </button>
              {file && (
                <button className="btn btn-secondary" onClick={handleReset}>
                  Clear
                </button>
              )}
            </div>
          </div>
        )}

        {mode === 'qr' && result && (
          <div>
            <AadhaarResult result={result} />
            <div className="action-buttons center">
              <button className="btn btn-secondary" onClick={handleReset}>
                Decode Another
              </button>
            </div>
          </div>
        )}
      </main>

      <footer className="app-footer">
        <p>Data is processed locally and never stored.</p>
      </footer>
    </div>
  );
}
